# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import os
import json
from collections import defaultdict

app = Flask(__name__)

# In-memory storage for labels
labels_storage = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    annotation = data.get('annotation')

    if image_id and annotation:
        labels_storage[image_id].append(annotation)
        return jsonify({"status": "success"}), 200
    else:
        return jsonify({"status": "error", "message": "Missing parameters"}), 400

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, annotations in labels_storage.items():
        if len(annotations) > 0:
            majority_vote = max(set(annotations), key=annotations.count)
            aggregated_labels[image_id] = majority_vote
        else:
            aggregated_labels[image_id] = None

    return jsonify(aggregated_labels), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')